import{_ as a,r as i,o as s,c as l,a as r,b as d,e as n,d as o}from"./app-BTM0SXbh.js";const h={},g={href:"https://cread.jd.com/read/startRead.action?bookId=30746878&readType=1&utm_source=chatgpt.com",target:"_blank",rel:"noopener noreferrer"},p={href:"https://cread.jd.com/read/startRead.action?bookId=30746878&readType=1&utm_source=chatgpt.com",target:"_blank",rel:"noopener noreferrer"};function u(b,t){const e=i("ExternalLinkIcon");return s(),l("div",null,[t[10]||(t[10]=r("h2",{id:"性能-—-总体结构与主线",tabindex:"-1"},[r("a",{class:"header-anchor",href:"#性能-—-总体结构与主线","aria-hidden":"true"},"#"),d(" 性能 — 总体结构与主线")],-1)),t[11]||(t[11]=r("p",null,"主要围绕 Web 应用的性能问题展开，如下：",-1)),r("ol",null,[t[3]||(t[3]=r("li",null,"性能评估模型",-1)),t[4]||(t[4]=r("li",null,"从 URL 到图像：网络 + 渲染路径 2.1 网络 2.2 渲染",-1)),t[5]||(t[5]=r("li",null,"内存管理 3.1 GC 算法 3.2 内存泄漏",-1)),t[6]||(t[6]=r("li",null,"极限运算性能",-1)),r("li",null,[t[1]||(t[1]=d("总结 (",-1)),r("a",g,[t[0]||(t[0]=d("参考前端技术架构与工程",-1)),n(e)]),t[2]||(t[2]=d(")",-1))])]),t[12]||(t[12]=o('<p>下面逐节拆解重点与理解。</p><h2 id="_1-性能评估模型" tabindex="-1"><a class="header-anchor" href="#_1-性能评估模型" aria-hidden="true">#</a> 1.性能评估模型</h2><h3 id="核心目的" tabindex="-1"><a class="header-anchor" href="#核心目的" aria-hidden="true">#</a> 核心目的</h3><p>在做性能优化之前，首先要有一个衡量标准或模型，即“性能是什么”以及“如何评估”。这节旨在建立性能评估的视角与度量方式。</p><table><thead><tr><th><strong>指标</strong></th><th><strong>全称</strong></th><th><strong>优秀阈值</strong></th><th><strong>状态核对</strong></th></tr></thead><tbody><tr><td><strong>FCP</strong></td><td>First Contentful Paint</td><td><strong>&lt; 1.8s</strong></td><td>标志着用户看到屏幕有实际内容。</td></tr><tr><td><strong>LCP</strong></td><td>Largest Contentful Paint</td><td><strong>&lt; 2.5s</strong></td><td>核心指标，反映感知加载速度。</td></tr><tr><td><strong>FID</strong></td><td>First Input Delay</td><td><strong>&lt; 100ms</strong></td><td><strong>已过时</strong>。Google 已于 2024 年 3 月将其从核心指标中移除。</td></tr><tr><td><strong>INP</strong></td><td><strong>Interaction to Next Paint</strong></td><td><strong>&lt; 200ms</strong></td><td>这是目前的<strong>新标杆</strong>，衡量全生命周期的交互响应。</td></tr><tr><td><strong>CLS</strong></td><td>Cumulative Layout Shift</td><td><strong>&lt; 0.1</strong></td><td>衡量视觉稳定性，数值越小越稳。</td></tr><tr><td><strong>TTI</strong></td><td>Time to Interactive</td><td><strong>&lt; 3.8s</strong></td><td>反映页面何时真正可用。</td></tr><tr><td><strong>TBT</strong></td><td>Total Blocking Time</td><td><strong>&lt; 200ms</strong></td><td>通常作为分析 LCP 和 TTI 差值的关键参考。</td></tr></tbody></table><p><strong>FID 的局限性</strong> ：它只测量用户“第一次”点击的延迟。如果用户第一次点击很快，但之后的滚动、输入卡顿，FID 依然会显示优秀（绿色）。这存在“幸存者偏差”。</p><p><strong>INP 的优势</strong> ：它观察用户在页面上进行的所有交互（点击、触摸、按键），并取其中最差（或接近最差）的一个响应时间。它能更真实地反映页面是否“顺滑”。</p><h3 id="关键信息点与思考" tabindex="-1"><a class="header-anchor" href="#关键信息点与思考" aria-hidden="true">#</a> 关键信息点与思考</h3><ul><li><strong>性能指标</strong>：可包括首屏时间、交互响应时间、帧率、内存占用、首字节时间 (TTFB)、总资源大小等。</li><li><strong>性能预算 / 性能目标</strong>：给每个页面或关键路径设置性能预算，比如最大资源大小、关键资源加载时间等。</li><li><strong>关键路径</strong>：分析从请求发起到页面完成渲染的路径中，哪些环节是“瓶颈”（网络、脚本阻塞、样式计算、布局、重绘等）。</li><li><strong>量化 vs 定性</strong>：性能评估既要有定性的用户感知，也要有定量的数据支持；比如页面流畅度 vs 帧率曲线、性能曲线图。</li></ul><blockquote><p>这个模型的意义在于：优化必须基于可度量、可追踪的目标，而不是盲目调整。</p></blockquote><hr><h2 id="_2-从-url-到-图像-网络-渲染流程" tabindex="-1"><a class="header-anchor" href="#_2-从-url-到-图像-网络-渲染流程" aria-hidden="true">#</a> 2 从 URL 到 图像（网络 + 渲染流程）</h2><p>这一节是性能优化的“核心链路”分析：从资源请求到最终内容在屏幕上呈现，涉及两个大阶段 —— 网络层面 + 渲染层面。</p><h3 id="_2-1-网络" tabindex="-1"><a class="header-anchor" href="#_2-1-网络" aria-hidden="true">#</a> 2.1 网络</h3><h4 id="关键因素-优化策略" tabindex="-1"><a class="header-anchor" href="#关键因素-优化策略" aria-hidden="true">#</a> 关键因素 &amp; 优化策略</h4><ul><li><strong>请求数量与资源合并 / 拆分</strong>：过多的小资源会增加 HTTP 请求开销；但又不能将所有资源打包过大。</li><li><strong>资源优先级 &amp; 延迟加载 / 懒加载</strong>：关键资源优先加载，非关键图片 / 脚本延后加载。</li><li><strong>缓存策略</strong>：合理设置 HTTP 缓存、CDN 分发、版本号、缓存失效策略。</li><li><strong>网络延迟与带宽</strong>：人为缩短链路（CDN、边缘部署、减少跳数）、压缩资源（gzip / brotli / 压缩图片 / svg / WebP）</li><li><strong>预加载 / 预连接 / DNS 预取</strong>：使用 <code>&lt;link rel=&quot;preload&quot;&gt;</code>、<code>&lt;link rel=&quot;prefetch&quot;&gt;</code>、<code>dns-prefetch</code> 等机制提前准备资源。</li><li><strong>资源压缩 / 精灵图 / 合图 / 雪碧图 / WebP / SVG</strong> 等优化手段。</li></ul>',16)),r("p",null,[t[8]||(t[8]=d("这部分主要从“URL 发起请求”到“资源加载完成”这一段链路来拆解网络性能的影响因素。 (",-1)),r("a",p,[t[7]||(t[7]=d("Cread",-1)),n(e)]),t[9]||(t[9]=d(")",-1))]),t[13]||(t[13]=o('<h4 id="前端网络优化策略" tabindex="-1"><a class="header-anchor" href="#前端网络优化策略" aria-hidden="true">#</a> 前端网络优化策略</h4><table><thead><tr><th>整体架构</th><th>前端</th></tr></thead><tbody><tr><td>使用持久连接</td><td>压缩文件体积</td></tr><tr><td>使用 CDN</td><td>合并小体积文件，使用雪碧图和字体图标避免不必要的下载</td></tr><tr><td>无法合并的小体积文件使用 HTTP combo</td><td>避免不必要的下载</td></tr><tr><td>控制域名数目</td><td>合理使用缓存</td></tr><tr><td></td><td>按需加载</td></tr></tbody></table><h3 id="_2-2-渲染" tabindex="-1"><a class="header-anchor" href="#_2-2-渲染" aria-hidden="true">#</a> 2.2 渲染</h3><p>在资源被加载之后，浏览器还要执行 CSS / JS / 布局 / 绘制 / 合成等操作，这里是“资源”变成“可视内容”的关键路径。</p><h4 id="关键因素-优化方向" tabindex="-1"><a class="header-anchor" href="#关键因素-优化方向" aria-hidden="true">#</a> 关键因素 &amp; 优化方向</h4><ul><li><strong>样式计算 / CSS 选择器效率</strong>：尽量使用简单、性能优的选择器，减少复杂的层级选择。</li><li><strong>布局 (Layout / Reflow)、重排 / 重绘 (Repaint)</strong>：避免频繁触发布局 / 重排；批量更改样式、使用 <code>transform</code> / <code>opacity</code> 优化动画。</li><li><strong>合成 (Composite / GPU 加速)</strong>：合理使用 GPU 图层，让某些元素单独成图层以减少重绘。</li><li><strong>避免主线程阻塞</strong>：避免长任务 (Long Task)、避免过大 JS 执行阻塞浏览器渲染。</li><li><strong>渲染流水线优化</strong>：Critical CSS（关键 CSS）、CSS 先行 / 延后加载、JS 延迟 / 异步执行。</li><li><strong>分层 / 分块渲染</strong>：对首屏内容优先渲染，其它部分延后。</li></ul><p>这部分是经典 “Critical Rendering Path”（关键渲染路径）思想的体现：尽量压缩从 HTML → CSS → JS → 布局 → 绘制 → 合成为图像的时延。</p><hr><h2 id="_3-内存管理" tabindex="-1"><a class="header-anchor" href="#_3-内存管理" aria-hidden="true">#</a> 3 内存管理</h2><p>性能不仅是“响应 / 渲染速度”，还涉及长期运行、用户操作过程中资源使用是否健康。内存管理就是关注应用“常驻”状态的性能。</p><h3 id="_3-1-gc-算法" tabindex="-1"><a class="header-anchor" href="#_3-1-gc-算法" aria-hidden="true">#</a> 3.1 GC 算法</h3><h4 id="重点内容" tabindex="-1"><a class="header-anchor" href="#重点内容" aria-hidden="true">#</a> 重点内容</h4><ul><li>垃圾回收机制原理：标记-清除 (Mark-Sweep)、标记-整理 (Mark-Compact)、分代 GC 等。</li><li>不同 GC 算法的适用场景与性能特征：老年代、年轻代的切换、Minor GC / Major GC 的开销差异。</li><li>如何减少 GC 负担：减少临时对象、避免频繁创建销毁大量对象、对象池 / 复用等策略。</li></ul><p>这部分让你理解：JavaScript 引擎中 GC 不是“黑盒”，其行为会对性能产生不可忽视的影响。</p><h3 id="_3-2-内存泄漏" tabindex="-1"><a class="header-anchor" href="#_3-2-内存泄漏" aria-hidden="true">#</a> 3.2 内存泄漏</h3><h4 id="重点内容-1" tabindex="-1"><a class="header-anchor" href="#重点内容-1" aria-hidden="true">#</a> 重点内容</h4><ul><li>常见内存泄漏类型：闭包泄漏、未移除的事件监听、定时器 / 回调未清理、DOM 引用未释放、全局变量、缓存对象持续增长等。</li><li>如何检测内存泄漏：使用浏览器开发者工具的 Heap Profiler、快照对比、分配剖析 (Allocation Profiling)、Timeline 追踪。</li><li>解决策略：及时销毁、取消绑定、弱引用 (WeakMap / WeakSet)、合理作用域控制、复用对象池等。</li></ul><p>强调：长期运行的页面／单页应用如果忽略内存泄漏问题，会随着使用时间推移导致性能大幅下降甚至浏览器崩溃。</p><hr><h2 id="_4-极限运算性能" tabindex="-1"><a class="header-anchor" href="#_4-极限运算性能" aria-hidden="true">#</a> 4 极限运算性能</h2><p>这一节偏向“高计算 / 大数据 / 复杂运算”场景下的性能处理策略。</p><h3 id="关键点与策略" tabindex="-1"><a class="header-anchor" href="#关键点与策略" aria-hidden="true">#</a> 关键点与策略</h3><ul><li><strong>Web Worker / Worker Threads</strong>：将计算密集型任务放到后台线程，避免主线程卡顿。</li><li><strong>分片 / 任务拆分</strong>：将大任务拆成多个小任务，让浏览器有喘息机会保持主线程响应性。</li><li><strong>GPU / WebGL / GPU 加速</strong>：对于图形、动画、计算密集型任务，尝试使用 GPU 加速计算。</li><li><strong>缓存 / 结果复用</strong>：如果计算有重复子任务，可缓存其结果避免重复计算。</li><li><strong>懒计算 / 按需计算</strong>：只有在必要时才触发计算，不要过早或过多地执行复杂逻辑。</li></ul><p>当应用遇到极限场景时（如大量数据处理、复杂动画、图形渲染等），应该有性能策略可用，而不是一味地“优化网络/渲染”那一路径。</p><h3 id="_5-总结" tabindex="-1"><a class="header-anchor" href="#_5-总结" aria-hidden="true">#</a> 5 总结</h3><table><thead><tr><th>优化目标</th><th>原理方向</th></tr></thead><tbody><tr><td>加载更快</td><td>减少 HTTP 请求、启用缓存、压缩资源、懒加载</td></tr><tr><td>渲染更快</td><td>减少回流重绘、合理使用合成层</td></tr><tr><td>JS 更快</td><td>避免长任务、使用 Web Worker</td></tr><tr><td>首屏更快</td><td>SSR / SSG / prefetch / preconnect</td></tr><tr><td>内存更低</td><td>避免内存泄漏（闭包、DOM 引用）</td></tr></tbody></table><p>性能优化是一个全链路、持续的过程。不能只盯一个环节（如网络或 JS），而需从资源获取 → 渲染 → 运行时 → 长期稳定性 → 计算性能多个维度统筹考虑。</p>',27))])}const f=a(h,[["render",u],["__file","optimise.html.vue"]]);export{f as default};
